  ('medical-tech-moex-20630', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '如果曲細精管 (Semiferous tubules) 只有Sertoli細胞，則臨床上病人會如何？ 不育 (infertility)    睪丸炎 (orchitis) Leydig細胞腫瘤 (Leydig cell tumor)  精液中精子數目稍減', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:15+00:00", "source_pdf_sha1": "410a76c9c225", "answer_pdf_sha1": "9fe68df2e674", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 49, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
